// ─── QUICK VIEW MODAL ─────────────────────────────────────────────────────────
function QuickViewModal({ product, onClose }) {
  const { addToCart, toggleWishlist, wishlist } = useContext(CartCtx);
  const [qty, setQty] = useState(1);
  const [selectedColor, setSelectedColor] = useState(product?.colors?.[0]);
  const wished = wishlist.includes(product?.id);

  useEffect(() => { if (product) { setQty(1); setSelectedColor(product.colors?.[0]); } }, [product]);

  return (
    <AnimatePresence>
      {product && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
          className="fixed inset-0 z-[150] flex items-center justify-center p-4" style={{ background: "rgba(28,20,16,0.75)", backdropFilter: "blur(6px)" }} onClick={onClose}
        >
          <motion.div initial={{ scale: 0.85, y: 30, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.85, y: 30, opacity: 0 }}
            transition={{ type: "spring", stiffness: 300, damping: 28 }}
            className="w-full max-w-4xl rounded-3xl overflow-hidden shadow-2xl flex flex-col md:flex-row max-h-[90vh] bg-white"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="md:w-1/2 h-72 md:h-auto relative overflow-hidden">
              <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
              {product.badge && <span className={`absolute top-4 left-4 text-white text-xs font-bold px-3 py-1 rounded-full ${product.badge === "SALE" ? "bg-[#B8743C]" : "bg-[#1C1410]"}`}>{product.badge}</span>}
            </div>
            <div className="md:w-1/2 p-8 flex flex-col overflow-y-auto">
              <button onClick={onClose} className="self-end w-9 h-9 rounded-full bg-[#F5EFE6] hover:bg-red-100 hover:text-red-500 flex items-center justify-center text-[#1C1410]/60 transition-colors mb-4">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <span className="text-[#B8743C] text-xs font-bold uppercase tracking-widest mb-2">{product.category}</span>
              <h3 className="font-serif text-3xl font-bold mb-3 text-[#1C1410]">{product.name}</h3>
              <div className="flex items-center gap-2 mb-4">
                <Stars count={product.rating} />
                <span className="text-xs text-gray-400">({product.reviews} reviews)</span>
              </div>
              <p className="text-sm leading-relaxed mb-6 text-[#1C1410]/70">{product.desc}</p>
              <div className="flex items-baseline gap-3 mb-6 flex-wrap">
                <span className="text-3xl font-bold text-[#1C1410]">{fmtNaira(product.price)}</span>
                {product.oldPrice && <span className="text-lg text-gray-400 line-through">{fmtNaira(product.oldPrice)}</span>}
                {product.oldPrice && <span className="text-sm text-[#6B7A5E] font-semibold">Save {fmtNaira(product.oldPrice - product.price)}</span>}
              </div>

              {product.colors && (
                <div className="mb-6">
                  <p className="text-sm font-semibold mb-2 text-[#1C1410]/80">Finish</p>
                  <div className="flex gap-2">
                    {product.colors.map((c) => (
                      <button key={c} onClick={() => setSelectedColor(c)} className={`w-8 h-8 rounded-full border-2 transition-all ${selectedColor === c ? "border-[#B8743C] scale-110" : "border-transparent"}`} style={{ background: c, boxShadow: "inset 0 0 0 1px rgba(0,0,0,0.1)" }} />
                    ))}
                  </div>
                </div>
              )}

              <div className="mb-6">
                <p className="text-sm font-semibold mb-2 text-[#1C1410]/80">Quantity</p>
                <div className="flex items-center gap-3">
                  <button onClick={() => setQty((q) => Math.max(1, q - 1))} className="w-9 h-9 rounded-full border border-[#D9C9A8] flex items-center justify-center hover:border-[#B8743C] hover:text-[#B8743C] transition-colors">−</button>
                  <span className="w-8 text-center font-bold text-[#1C1410]">{qty}</span>
                  <button onClick={() => setQty((q) => q + 1)} className="w-9 h-9 rounded-full border border-[#D9C9A8] flex items-center justify-center hover:border-[#B8743C] hover:text-[#B8743C] transition-colors">+</button>
                </div>
              </div>

              <div className="flex gap-3 mt-auto">
                <motion.button whileTap={{ scale: 0.95 }} onClick={() => { for (let i = 0; i < qty; i++) addToCart(product); onClose(); }}
                  className="flex-1 bg-[#1C1410] hover:bg-[#B8743C] text-white font-bold py-4 rounded-xl transition-colors"
                >Add to Cart</motion.button>
                <motion.button whileTap={{ scale: 0.95 }} onClick={() => toggleWishlist(product.id)}
                  className={`w-14 h-14 rounded-xl border flex items-center justify-center transition-colors ${wished ? "bg-red-50 border-red-200 text-red-500" : "border-[#D9C9A8] text-[#1C1410]/60 hover:border-red-300 hover:text-red-500"}`}
                ><svg className="w-5 h-5" fill={wished ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg></motion.button>
              </div>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

// ─── CART DRAWER ──────────────────────────────────────────────────────────────
